#pragma once

static const char *WEB_INDEX_HTML =
"<!doctype html><html><head><meta charset='utf-8'/>"
"<meta name='viewport' content='width=device-width,initial-scale=1'/>"
"<title>ESP32-C3 Device Config</title>"
"<style>"
":root{--bg:#f4f1e8;--card:#fffdf7;--line:#d8cdb8;--ink:#1f2a2c;--muted:#5f6766;--accent:#c65d32;--ok:#176f41;--err:#a62828}"
"body{margin:0;font-family:Georgia,serif;background:radial-gradient(circle at top,#fff7e6 0,#f4f1e8 45%,#ebe6db 100%);color:var(--ink)}"
".wrap{max-width:1180px;margin:0 auto;padding:20px}"
".hero{display:flex;justify-content:space-between;gap:16px;align-items:flex-start;margin-bottom:18px}"
".title{font-size:30px;line-height:1.1;margin:0}.muted{color:var(--muted)}"
".grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:14px}"
".card{background:var(--card);border:1px solid var(--line);border-radius:18px;padding:16px;box-shadow:0 10px 25px rgba(84,66,40,.06)}"
".card h3{margin:0 0 10px;font-size:18px}.row{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.row3{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px}"
"label{display:block;font-size:13px;font-weight:700;margin:8px 0 4px} input,select,button,textarea{font:inherit}"
"input,select,textarea{width:100%;box-sizing:border-box;padding:9px 10px;border:1px solid var(--line);border-radius:10px;background:#fff}"
"textarea{min-height:180px;font-family:Consolas,monospace;font-size:13px}"
"button{border:0;border-radius:999px;padding:10px 14px;background:var(--ink);color:#fff;cursor:pointer}"
".alt{background:#9d8d73}.warn{background:var(--accent)}.danger{background:#7f1d1d}"
".toolbar{display:flex;gap:10px;flex-wrap:wrap}.pill{display:inline-block;padding:5px 9px;border-radius:999px;background:#efe4cf;font-size:12px;margin-right:6px;margin-bottom:6px}"
".item{border:1px dashed var(--line);border-radius:14px;padding:12px;margin-top:10px;background:#fff}.itemhead{display:flex;justify-content:space-between;align-items:center;gap:10px}"
".mono{font-family:Consolas,monospace}.ok{color:var(--ok)}.err{color:var(--err)} pre{white-space:pre-wrap;margin:0}"
"</style></head><body><div class='wrap'>"
"<div class='hero'><div><h1 class='title'>ESP32-C3 Device Configurator</h1><div class='muted'>Mixed outputs, buttons, inputs and sensors from one firmware build.</div></div>"
"<div><div id='runtime' class='pill'>Loading runtime...</div><div id='msg' class='muted'></div></div></div>"
"<div class='toolbar' style='margin-bottom:14px'>"
"<button onclick='scanWifi()'>Scan Wi-Fi</button>"
"<button onclick='saveAndApply()'>Save + Apply</button>"
"<button class='alt' onclick='applyOnly()'>Apply only</button>"
"<button class='danger' onclick='factoryReset()'>Factory reset</button>"
"</div>"
"<div class='grid'>"
"<section class='card'><h3>Connectivity</h3><div class='row'>"
"<div><label>Device name</label><input id='device_name'/></div>"
"<div><label>Hostname</label><input id='hostname'/></div></div>"
"<div class='row'><div><label>AP SSID</label><input id='ap_ssid'/></div><div><label>AP Password</label><input id='ap_pass'/></div></div>"
"<div class='row'><div><label>Wi-Fi scan</label><select id='wifi_scan_list'></select></div><div><label>STA SSID</label><input id='sta_ssid'/></div></div>"
"<div><label>STA Password</label><input id='sta_pass' type='password'/></div>"
"<div class='row3'><div><label>MQTT host</label><input id='mqtt_host'/></div><div><label>MQTT port</label><input id='mqtt_port' type='number'/></div><div><label>MQTT user</label><input id='mqtt_user'/></div></div>"
"<div class='row'><div><label>MQTT password</label><input id='mqtt_pass' type='password'/></div><div><label>Topic prefix</label><input id='mqtt_topic_prefix'/></div></div>"
"<div class='row3'><div><label>Client ID</label><input id='mqtt_client_id'/></div><div><label>Discovery prefix</label><input id='mqtt_discovery_prefix'/></div><div><label>Board profile</label><input id='board_profile' disabled/></div></div>"
"<div class='row3'><div><label><input id='mqtt_enable' type='checkbox' style='width:auto'/> MQTT enabled</label></div><div><label><input id='mqtt_discovery' type='checkbox' style='width:auto'/> HA discovery</label></div><div><label><input id='mqtt_retain' type='checkbox' style='width:auto'/> Retain</label></div></div>"
"</section>"
"<section class='card'><h3>GPIO Policy</h3><div id='gpio_summary' class='muted'>Loading...</div><div style='margin-top:10px'>"
"<span class='pill mono'>allowed: 0 1 3 4 5 6 7 10</span><span class='pill mono'>reserved reset: 9</span><span class='pill mono'>USB: 18 19</span><span class='pill mono'>UART: 20 21</span></div>"
"<div style='margin-top:14px'><label>Runtime status</label><pre id='runtime_status' class='mono muted'></pre></div></section>"
"</div>"
"<div class='grid' style='margin-top:14px'>"
"<section class='card'><h3>Outputs</h3><div class='toolbar'><button onclick='addOutput()'>Add output</button></div><div id='outputs'></div></section>"
"<section class='card'><h3>Inputs</h3><div class='toolbar'><button onclick='addInput()'>Add input</button></div><div id='inputs'></div></section>"
"<section class='card'><h3>Buttons</h3><div class='toolbar'><button onclick='addButton()'>Add button</button></div><div id='buttons'></div></section>"
"<section class='card'><h3>Sensors</h3><div class='toolbar'><button onclick='addSensor()'>Add sensor</button></div><div id='sensors'></div></section>"
"</div>"
"<section class='card' style='margin-top:14px'><h3>Raw Config</h3><div class='muted'>Advanced view of the normalized config that will be saved.</div><textarea id='raw_cfg' readonly></textarea></section>"
"<script>"
"const ALLOWED_GPIOS=[0,1,3,4,5,6,7,10];"
"const OUTPUT_TYPES=['relay','pwm','ws2812'];"
"const INPUT_ROLES=['generic_binary','motion','presence','contact','limit'];"
"const PULLS=['up','down','none'];"
"const SENSOR_TYPES=['ds18b20_bus','aht20','sht3x','bme280'];"
"const BUTTON_ACTIONS=['none','master_toggle','master_on','master_off','toggle_output','set_output','dim_step_up','dim_step_down'];"
"let cfg=null;"
"function esc(v){return String(v==null?'':v).replace(/[&<>\"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[m]));}"
"function setMsg(msg,ok){const el=document.getElementById('msg');el.textContent=msg||'';el.className=ok?'ok':'err';}"
"function pick(v,d){return v===undefined||v===null?d:v;}"
"function ensure(){cfg.outputs=Array.isArray(cfg.outputs)?cfg.outputs:[];cfg.inputs=Array.isArray(cfg.inputs)?cfg.inputs:[];cfg.buttons=Array.isArray(cfg.buttons)?cfg.buttons:[];cfg.sensors=Array.isArray(cfg.sensors)?cfg.sensors:[];cfg.device=cfg.device||{};cfg.connectivity=cfg.connectivity||{};cfg.connectivity.ap=cfg.connectivity.ap||{};cfg.connectivity.sta=cfg.connectivity.sta||{};cfg.connectivity.mqtt=cfg.connectivity.mqtt||{};}"
"function gpioOptions(selected){return ALLOWED_GPIOS.map(g=>`<option value='${g}' ${Number(selected)===g?'selected':''}>GPIO${g}</option>`).join('');}"
"function simpleOptions(items,selected){return items.map(v=>`<option value='${esc(v)}' ${String(selected)===String(v)?'selected':''}>${esc(v)}</option>`).join('');}"
"function refreshRaw(){document.getElementById('raw_cfg').value=JSON.stringify(cfg,null,2);}"
"function setField(section,idx,key,value){cfg[section][idx][key]=value;render();}"
"function setNested(section,idx,parent,key,value){cfg[section][idx][parent]=cfg[section][idx][parent]||{};cfg[section][idx][parent][key]=value;render();}"
"function removeItem(section,idx){cfg[section].splice(idx,1);render();}"
"function renderOutputs(){document.getElementById('outputs').innerHTML=cfg.outputs.map((o,i)=>{const type=pick(o.type,'relay');return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||('output'+(i+1)))}</strong><button class='danger' onclick=\"removeItem('outputs',${i})\">Remove</button></div><div class='row'><div><label>ID</label><input value='${esc(o.id||'')}' oninput=\"setField('outputs',${i},'id',this.value)\"/></div><div><label>Name</label><input value='${esc(o.name||'')}' oninput=\"setField('outputs',${i},'name',this.value)\"/></div></div><div class='row3'><div><label>Type</label><select onchange=\"setField('outputs',${i},'type',this.value)\">${simpleOptions(OUTPUT_TYPES,type)}</select></div><div><label>GPIO</label><select onchange=\"setField('outputs',${i},'gpio',Number(this.value))\">${gpioOptions(pick(o.gpio,0))}</select></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange=\"setField('outputs',${i},'enabled',this.checked)\" style='width:auto'/> Enabled</label></div></div>${type==='relay'?`<div class='row'><div><label>Active level</label><select onchange=\"setField('outputs',${i},'active_level',Number(this.value))\"><option value='1' ${Number(pick(o.active_level,1))===1?'selected':''}>1</option><option value='0' ${Number(pick(o.active_level,1))===0?'selected':''}>0</option></select></div><div><label><input type='checkbox' ${o.default_on?'checked':''} onchange=\"setField('outputs',${i},'default_on',this.checked)\" style='width:auto'/> Default ON</label></div></div>`:''}${type==='pwm'?`<div class='row3'><div><label>Freq Hz</label><input type='number' value='${esc(pick(o.freq_hz,1000))}' oninput=\"setField('outputs',${i},'freq_hz',Number(this.value||0))\"/></div><div><label>Default level</label><input type='number' min='0' max='100' value='${esc(pick(o.default_level,0))}' oninput=\"setField('outputs',${i},'default_level',Number(this.value||0))\"/></div><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange=\"setField('outputs',${i},'inverted',this.checked)\" style='width:auto'/> Inverted</label></div></div>`:''}${type==='ws2812'?`<div class='row3'><div><label>Pixels</label><input type='number' value='${esc(pick(o.pixel_count,1))}' oninput=\"setField('outputs',${i},'pixel_count',Number(this.value||1))\"/></div><div><label>Color order</label><input value='${esc(pick(o.color_order,'GRB'))}' oninput=\"setField('outputs',${i},'color_order',this.value)\"/></div><div><label><input type='checkbox' ${o.default_power_on?'checked':''} onchange=\"setField('outputs',${i},'default_power_on',this.checked)\" style='width:auto'/> Default ON</label></div></div>`:''}</div>`;}).join('');}"
"function renderInputs(){document.getElementById('inputs').innerHTML=cfg.inputs.map((o,i)=>`<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||('input'+(i+1)))}</strong><button class='danger' onclick=\"removeItem('inputs',${i})\">Remove</button></div><div class='row'><div><label>ID</label><input value='${esc(o.id||'')}' oninput=\"setField('inputs',${i},'id',this.value)\"/></div><div><label>Name</label><input value='${esc(o.name||'')}' oninput=\"setField('inputs',${i},'name',this.value)\"/></div></div><div class='row3'><div><label>GPIO</label><select onchange=\"setField('inputs',${i},'gpio',Number(this.value))\">${gpioOptions(pick(o.gpio,0))}</select></div><div><label>Role</label><select onchange=\"setField('inputs',${i},'role',this.value)\">${simpleOptions(INPUT_ROLES,pick(o.role,'generic_binary'))}</select></div><div><label>Pull</label><select onchange=\"setField('inputs',${i},'pull',this.value)\">${simpleOptions(PULLS,pick(o.pull,'up'))}</select></div></div><div class='row'><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange=\"setField('inputs',${i},'inverted',this.checked)\" style='width:auto'/> Inverted</label></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange=\"setField('inputs',${i},'enabled',this.checked)\" style='width:auto'/> Enabled</label></div></div></div>`).join('');}"
"function actionEditor(section,idx,which,a){const cur=(a||{});return `<div class='row3'><div><label>${which} action</label><select onchange=\"setNested('${section}',${idx},'actions','${which}',Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}), {type:this.value}))\">${simpleOptions(BUTTON_ACTIONS,pick(cur.type,'none'))}</select></div><div><label>${which} target</label><input value='${esc(pick(cur.target,''))}' oninput=\"setNested('${section}',${idx},'actions','${which}',Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}), {target:this.value}))\"/></div><div><label>${which} step/value</label><input value='${esc(cur.step!==undefined?cur.step:(cur.value!==undefined?cur.value:''))}' oninput=\"const obj=Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{}); if(obj.type==='set_output'){obj.value=(this.value==='true'||this.value==='1'||this.value==='on');} else {obj.step=Number(this.value||10);} setNested('${section}',${idx},'actions','${which}',obj)\"/></div></div>`;}"
"function renderButtons(){document.getElementById('buttons').innerHTML=cfg.buttons.map((o,i)=>`<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||('button'+(i+1)))}</strong><button class='danger' onclick=\"removeItem('buttons',${i})\">Remove</button></div><div class='row'><div><label>ID</label><input value='${esc(o.id||'')}' oninput=\"setField('buttons',${i},'id',this.value)\"/></div><div><label>Name</label><input value='${esc(o.name||'')}' oninput=\"setField('buttons',${i},'name',this.value)\"/></div></div><div class='row3'><div><label>GPIO</label><select onchange=\"setField('buttons',${i},'gpio',Number(this.value))\">${gpioOptions(pick(o.gpio,0))}</select></div><div><label>Pull</label><select onchange=\"setField('buttons',${i},'pull',this.value)\">${simpleOptions(PULLS,pick(o.pull,'up'))}</select></div><div><label>Long press ms</label><input type='number' value='${esc(pick(o.long_press_ms,1000))}' oninput=\"setField('buttons',${i},'long_press_ms',Number(this.value||1000))\"/></div></div><div class='row'><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange=\"setField('buttons',${i},'inverted',this.checked)\" style='width:auto'/> Inverted</label></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange=\"setField('buttons',${i},'enabled',this.checked)\" style='width:auto'/> Enabled</label></div></div>${actionEditor('buttons',i,'short',(o.actions||{}).short)}${actionEditor('buttons',i,'long',(o.actions||{}).long)}</div>`).join('');}"
"function renderSensors(){document.getElementById('sensors').innerHTML=cfg.sensors.map((o,i)=>{const t=pick(o.type,'ds18b20_bus');return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||('sensor'+(i+1)))}</strong><button class='danger' onclick=\"removeItem('sensors',${i})\">Remove</button></div><div class='row'><div><label>ID</label><input value='${esc(o.id||'')}' oninput=\"setField('sensors',${i},'id',this.value)\"/></div><div><label>Name</label><input value='${esc(o.name||'')}' oninput=\"setField('sensors',${i},'name',this.value)\"/></div></div><div class='row3'><div><label>Type</label><select onchange=\"setField('sensors',${i},'type',this.value)\">${simpleOptions(SENSOR_TYPES,t)}</select></div><div><label>Poll sec</label><input type='number' value='${esc(pick(o.poll_interval_sec,30))}' oninput=\"setField('sensors',${i},'poll_interval_sec',Number(this.value||30))\"/></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange=\"setField('sensors',${i},'enabled',this.checked)\" style='width:auto'/> Enabled</label></div></div>${t==='ds18b20_bus'?`<div><label>GPIO</label><select onchange=\"setField('sensors',${i},'gpio',Number(this.value))\">${gpioOptions(pick(o.gpio,0))}</select></div>`:`<div class='row3'><div><label>SDA</label><select onchange=\"setField('sensors',${i},'sda_gpio',Number(this.value))\">${gpioOptions(pick(o.sda_gpio,0))}</select></div><div><label>SCL</label><select onchange=\"setField('sensors',${i},'scl_gpio',Number(this.value))\">${gpioOptions(pick(o.scl_gpio,1))}</select></div><div><label>Address</label><input value='${esc(pick(o.address,t==='aht20'?56:t==='sht3x'?68:118))}' oninput=\"setField('sensors',${i},'address',Number(this.value||0))\"/></div></div>`}</div>`;}).join('');}"
"function renderMeta(){document.getElementById('device_name').value=pick(cfg.device.name,'');document.getElementById('hostname').value=pick(cfg.connectivity.hostname,'esp32-c3');document.getElementById('ap_ssid').value=pick(cfg.connectivity.ap.ssid,'ESP32-SETUP');document.getElementById('ap_pass').value=pick(cfg.connectivity.ap.pass,'');document.getElementById('sta_ssid').value=pick(cfg.connectivity.sta.ssid,'');document.getElementById('sta_pass').value=pick(cfg.connectivity.sta.pass,'');document.getElementById('mqtt_host').value=pick(cfg.connectivity.mqtt.host,'');document.getElementById('mqtt_port').value=pick(cfg.connectivity.mqtt.port,1883);document.getElementById('mqtt_user').value=pick(cfg.connectivity.mqtt.user,'');document.getElementById('mqtt_pass').value=pick(cfg.connectivity.mqtt.pass,'');document.getElementById('mqtt_topic_prefix').value=pick(cfg.connectivity.mqtt.topic_prefix,'');document.getElementById('mqtt_client_id').value=pick(cfg.connectivity.mqtt.client_id,'');document.getElementById('mqtt_discovery_prefix').value=pick(cfg.connectivity.mqtt.discovery_prefix,'homeassistant');document.getElementById('mqtt_enable').checked=cfg.connectivity.mqtt.enable===true;document.getElementById('mqtt_discovery').checked=cfg.connectivity.mqtt.discovery!==false;document.getElementById('mqtt_retain').checked=cfg.connectivity.mqtt.retain!==false;document.getElementById('board_profile').value=pick(cfg.device.board_profile,'esp32-c3-devkitm-1');}"
"function updateMetaFromInputs(){cfg.device.name=document.getElementById('device_name').value.trim();cfg.connectivity.hostname=document.getElementById('hostname').value.trim();cfg.connectivity.ap.ssid=document.getElementById('ap_ssid').value.trim();cfg.connectivity.ap.pass=document.getElementById('ap_pass').value;cfg.connectivity.sta.ssid=document.getElementById('sta_ssid').value.trim();cfg.connectivity.sta.pass=document.getElementById('sta_pass').value;cfg.connectivity.mqtt.enable=document.getElementById('mqtt_enable').checked;cfg.connectivity.mqtt.host=document.getElementById('mqtt_host').value.trim();cfg.connectivity.mqtt.port=Number(document.getElementById('mqtt_port').value||1883);cfg.connectivity.mqtt.user=document.getElementById('mqtt_user').value.trim();cfg.connectivity.mqtt.pass=document.getElementById('mqtt_pass').value;cfg.connectivity.mqtt.topic_prefix=document.getElementById('mqtt_topic_prefix').value.trim();cfg.connectivity.mqtt.client_id=document.getElementById('mqtt_client_id').value.trim();cfg.connectivity.mqtt.discovery_prefix=document.getElementById('mqtt_discovery_prefix').value.trim();cfg.connectivity.mqtt.discovery=document.getElementById('mqtt_discovery').checked;cfg.connectivity.mqtt.retain=document.getElementById('mqtt_retain').checked;}"
"function validateGpios(){const used={};const errors=[];const touch=(label,g)=>{if(g===undefined||g===null||g==='')return;const key=String(g);used[key]=used[key]||[];used[key].push(label);};cfg.outputs.forEach(o=>touch(`output ${o.id||o.name||'?'}`,o.gpio));cfg.inputs.forEach(o=>touch(`input ${o.id||o.name||'?'}`,o.gpio));cfg.buttons.forEach(o=>touch(`button ${o.id||o.name||'?'}`,o.gpio));cfg.sensors.forEach(o=>{if(o.type==='ds18b20_bus'){touch(`sensor ${o.id||o.name||'?'}`,o.gpio);}else{touch('i2c_sda',o.sda_gpio);touch('i2c_scl',o.scl_gpio);}});Object.entries(used).forEach(([gpio,list])=>{if(list.length>1 && !(list.every(v=>v==='i2c_sda')||list.every(v=>v==='i2c_scl'))) errors.push(`GPIO${gpio}: ${list.join(', ')}`);});document.getElementById('gpio_summary').innerHTML=errors.length?`<span class='err'>Conflicts:</span><br>${errors.map(esc).join('<br>')}`:`<span class='ok'>No GPIO conflicts detected.</span>`;}"
"function render(){ensure();renderMeta();renderOutputs();renderInputs();renderButtons();renderSensors();refreshRaw();validateGpios();}"
"function addOutput(){cfg.outputs.push({id:`out${cfg.outputs.length+1}`,name:`Output ${cfg.outputs.length+1}`,type:'relay',enabled:true,gpio:0,active_level:1,default_on:false});render();}"
"function addInput(){cfg.inputs.push({id:`in${cfg.inputs.length+1}`,name:`Input ${cfg.inputs.length+1}`,type:'digital',enabled:true,gpio:0,pull:'up',inverted:false,role:'generic_binary'});render();}"
"function addButton(){cfg.buttons.push({id:`btn${cfg.buttons.length+1}`,name:`Button ${cfg.buttons.length+1}`,enabled:true,gpio:0,pull:'up',inverted:false,long_press_ms:1000,actions:{short:{type:'master_toggle'},long:{type:'none'}}});render();}"
"function addSensor(){cfg.sensors.push({id:`sensor${cfg.sensors.length+1}`,name:`Sensor ${cfg.sensors.length+1}`,type:'ds18b20_bus',enabled:true,gpio:0,poll_interval_sec:30});render();}"
"async function loadStatus(){const [rt,mods]=await Promise.all([fetch('/api/runtime').then(r=>r.json()),fetch('/api/modules').then(r=>r.json())]);document.getElementById('runtime').textContent=`mode: ${rt.mode||'?'} | mqtt: ${rt.mqtt_connected?'connected':'offline'} | ap: ${rt.ap_ssid||'-'}`;document.getElementById('runtime_status').textContent=JSON.stringify(mods,null,2);}"
"async function loadCfg(){cfg=await fetch('/api/config').then(r=>r.json());ensure();render();await loadStatus();}"
"async function scanWifi(){try{const r=await fetch('/api/wifi/scan');const j=await r.json();const nets=j.networks||[];const sel=document.getElementById('wifi_scan_list');sel.innerHTML='<option value=\"\">Select network...</option>'+nets.map(n=>`<option value=\"${esc(n.ssid)}\">${esc(n.ssid)} (${n.rssi} dBm)</option>`).join('');sel.onchange=()=>{if(sel.value)document.getElementById('sta_ssid').value=sel.value;};setMsg(`Found ${nets.length} networks`,true);}catch(e){setMsg(String(e),false);}}"
"async function saveOnly(){updateMetaFromInputs();const r=await fetch('/api/config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(cfg)});const text=await r.text();if(!r.ok) throw new Error(text||('HTTP '+r.status));setMsg('Config saved',true);}"
"async function saveAndApply(){try{await saveOnly();const r=await fetch('/api/apply',{method:'POST'});if(!r.ok) throw new Error(await r.text());setMsg('Saved and apply scheduled',true);setTimeout(loadStatus,900);}catch(e){setMsg(String(e),false);}}"
"async function applyOnly(){try{const r=await fetch('/api/apply',{method:'POST'});if(!r.ok) throw new Error(await r.text());setMsg('Apply scheduled',true);setTimeout(loadStatus,900);}catch(e){setMsg(String(e),false);}}"
"async function factoryReset(){try{if(!confirm('Erase full device configuration and reboot?')) return;const r=await fetch('/api/factory-reset',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({confirm:'ERASE'})});if(!r.ok) throw new Error(await r.text());setMsg('Factory reset scheduled',true);}catch(e){setMsg(String(e),false);}}"
"window.setField=setField;window.setNested=setNested;window.removeItem=removeItem;window.addOutput=addOutput;window.addInput=addInput;window.addButton=addButton;window.addSensor=addSensor;window.scanWifi=scanWifi;window.saveAndApply=saveAndApply;window.applyOnly=applyOnly;window.factoryReset=factoryReset;"
"loadCfg();"
"</script></div></body></html>";
